// syncResult holds the outcome of syncing a single resource.
type syncResult struct {
	Resource string
	Count    int
	Err      error
	Duration time.Duration
}

func newSyncCmd(flags *rootFlags) *cobra.Command {
	var resources []string
	var full bool
	var since string
	var concurrency int
	var dbPath string
	var maxPages int

	cmd := &cobra.Command{
		Use:   "sync",
		Short: "Sync API data to local SQLite for offline search and analysis",
		Long: `Sync data from the API into a local SQLite database. Supports resumable
incremental sync (only fetches new data since last sync) and full resync.
Once synced, use the 'search' command for instant full-text search.`,
		Example: `  # Sync all resources
  slack-pp-cli sync

  # Sync specific resources only
  slack-pp-cli sync --resources channels,messages

  # Full resync (ignore previous checkpoint)
  slack-pp-cli sync --full

  # Incremental sync: only records from the last 7 days
  slack-pp-cli sync --since 7d

  # Parallel sync with 8 workers
  slack-pp-cli sync --concurrency 8`,
		RunE: func(cmd *cobra.Command, args []string) error {
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			c.NoCache = true

			if dbPath == "" {
				dbPath = defaultDBPath("slack-pp-cli")
			}

			db, err := store.Open(dbPath)
			if err != nil {
				return fmt.Errorf("opening local database: %w", err)
			}
			defer db.Close()

			// If no specific resources, sync top-level resources
			if len(resources) == 0 {
				resources = defaultSyncResources()
			}

			// --full: clear all sync cursors before starting
			if full {
				for _, resource := range resources {
					_ = db.SaveSyncState(resource, "", 0)
				}
			}

			// Resolve --since into an RFC3339 timestamp
			sinceTS := ""
			if since != "" {
				ts, err := parseSinceDuration(since)
				if err != nil {
					return fmt.Errorf("invalid --since value %q: %w", since, err)
				}
				sinceTS = ts.Format(time.RFC3339)
			}

			// Worker pool: produce resources, N workers consume
			if concurrency < 1 {
				concurrency = 4
			}

			started := time.Now()
			var workerResources []string
			syncMessages := false
			for _, resource := range resources {
				if resource == "messages" {
					syncMessages = true
					continue
				}
				workerResources = append(workerResources, resource)
			}

			work := make(chan string, len(workerResources))
			results := make(chan syncResult, len(resources))

			var wg sync.WaitGroup
			for i := 0; i < concurrency; i++ {
				wg.Add(1)
				go func() {
					defer wg.Done()
					for resource := range work {
						res := syncResource(c, db, resource, sinceTS, full, maxPages)
						results <- res
					}
				}()
			}

			// Enqueue all resources
			for _, resource := range workerResources {
				work <- resource
			}
			close(work)

			// Collect results in a separate goroutine
			go func() {
				wg.Wait()
				close(results)
			}()

			var totalSynced int
			var errCount int
			for res := range results {
				if res.Err != nil {
					if humanFriendly {
						fmt.Fprintf(os.Stderr, "  %s: error: %v\n", res.Resource, res.Err)
					}
					errCount++
				} else {
					if humanFriendly {
						fmt.Fprintf(os.Stderr, "  %s: %d synced (done)\n", res.Resource, res.Count)
					}
					totalSynced += res.Count
				}
			}
			if syncMessages {
				res := syncResource(c, db, "messages", sinceTS, full, maxPages)
				if res.Err != nil {
					if humanFriendly {
						fmt.Fprintf(os.Stderr, "  %s: error: %v\n", res.Resource, res.Err)
					}
					errCount++
				} else {
					if humanFriendly {
						fmt.Fprintf(os.Stderr, "  %s: %d synced (done)\n", res.Resource, res.Count)
					}
					totalSynced += res.Count
				}
			}

			elapsed := time.Since(started)
			fmt.Fprintf(os.Stderr, "Sync complete: %d records across %d resources (%.1fs)\n",
				totalSynced, len(resources), elapsed.Seconds())

			if errCount > 0 {
				return fmt.Errorf("%d resource(s) failed to sync", errCount)
			}
			return nil
		},
	}

	cmd.Flags().StringSliceVar(&resources, "resources", nil, "Comma-separated resource types to sync")
	cmd.Flags().BoolVar(&full, "full", false, "Full resync (ignore previous checkpoint)")
	cmd.Flags().StringVar(&since, "since", "", "Incremental sync duration (e.g. 7d, 24h, 1w, 30m)")
	cmd.Flags().IntVar(&concurrency, "concurrency", 4, "Number of parallel sync workers")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: ~/.local/share/slack-pp-cli/data.db)")
	cmd.Flags().IntVar(&maxPages, "max-pages", 10, "Maximum pages to fetch per resource (0 = unlimited)")

	return cmd
}

// syncResource handles the full paginated sync of a single resource.
// It resumes from the last cursor unless sinceTS or full mode overrides it.
func syncResource(c interface {
	Get(string, map[string]string) (json.RawMessage, error)
	RateLimit() float64
}, db *store.Store, resource, sinceTS string, full bool, maxPages int) syncResult {
	started := time.Now()

	if !humanFriendly {
		fmt.Fprintf(os.Stderr, `{"event":"sync_start","resource":"%s"}`+"\n", resource)
	}
	if resource == "messages" {
		return syncMessagesResource(c, db, sinceTS, full, started)
	}

	path := syncResourcePath(resource)
	var totalCount int

	// Resume cursor from sync_state (unless --full cleared it)
	existingCursor, lastSynced, _, _ := db.GetSyncState(resource)

	// Determine the since param value:
	// 1. Explicit --since flag takes priority
	// 2. Otherwise use last_synced_at from sync_state for incremental sync
	sinceParam := determineSinceParam()
	effectiveSince := sinceTS
	if effectiveSince == "" && !lastSynced.IsZero() && !full {
		effectiveSince = lastSynced.Format(time.RFC3339)
	}

	cursor := existingCursor
	pageSize := determinePaginationDefaults()

	var progressCount int64
	pagesFetched := 0

	for {
		params := map[string]string{}

		// Set page size
		params[pageSize.limitParam] = strconv.Itoa(pageSize.limit)

		// Set cursor for resume
		if cursor != "" {
			params[pageSize.cursorParam] = cursor
		}

		// Set since filter
		if effectiveSince != "" {
			params[sinceParam] = effectiveSince
		}

		data, err := c.Get(path, params)
		if err != nil {
			if !humanFriendly {
				fmt.Fprintf(os.Stderr, `{"event":"sync_error","resource":"%s","error":"%s"}`+"\n", resource, strings.ReplaceAll(err.Error(), `"`, `\"`))
			}
			return syncResult{Resource: resource, Count: totalCount, Err: fmt.Errorf("fetching %s: %w", resource, err), Duration: time.Since(started)}
		}

		// PATCH: detect Slack ok:false errors (e.g. missing_scope) before attempting to store.
		// Without this, error objects get stored as a single "record" and silently corrupt the store.
		var slackStatus struct {
			OK    bool   `json:"ok"`
			Error string `json:"error"`
		}
		if err := json.Unmarshal(data, &slackStatus); err == nil && !slackStatus.OK {
			errMsg := slackStatus.Error
			if errMsg == "" {
				errMsg = "unknown Slack API error"
			}
			if !humanFriendly {
				fmt.Fprintf(os.Stderr, `{"event":"sync_error","resource":"%s","error":"%s"}`+"\n", resource, errMsg)
			}
			return syncResult{Resource: resource, Count: totalCount, Err: fmt.Errorf("Slack API error for %s: %s", resource, errMsg), Duration: time.Since(started)}
		}

		// Try to extract items from the response.
		// Strategy: try array first, then common wrapper keys.
		items, nextCursor, hasMore := extractPageItems(data, pageSize.cursorParam)

		if len(items) == 0 {
			// Single object response - try to store as-is
			if err := upsertSingleObject(db, resource, data); err != nil {
				if !humanFriendly {
					fmt.Fprintf(os.Stderr, `{"event":"sync_error","resource":"%s","error":"%s"}`+"\n", resource, strings.ReplaceAll(err.Error(), `"`, `\"`))
				}
				return syncResult{Resource: resource, Err: err, Duration: time.Since(started)}
			}
			totalCount++
			break
		}

		// Batch upsert all items from this page
		if err := db.UpsertBatch(resource, items); err != nil {
			if !humanFriendly {
				fmt.Fprintf(os.Stderr, `{"event":"sync_error","resource":"%s","error":"%s"}`+"\n", resource, strings.ReplaceAll(err.Error(), `"`, `\"`))
			}
			return syncResult{Resource: resource, Count: totalCount, Err: fmt.Errorf("upserting batch for %s: %w", resource, err), Duration: time.Since(started)}
		}

		totalCount += len(items)
		atomic.AddInt64(&progressCount, int64(len(items)))

		// Progress reporting (include rate limit info when active)
		currentRate := c.RateLimit()
		if humanFriendly {
			if currentRate > 0 {
				fmt.Fprintf(os.Stderr, "\r  %s: %d synced [%.1f req/s]", resource, atomic.LoadInt64(&progressCount), currentRate)
			} else {
				fmt.Fprintf(os.Stderr, "\r  %s: %d synced", resource, atomic.LoadInt64(&progressCount))
			}
		} else {
			if currentRate > 0 {
				fmt.Fprintf(os.Stderr, `{"event":"sync_progress","resource":"%s","fetched":%d,"rate_rps":%.1f}`+"\n", resource, atomic.LoadInt64(&progressCount), currentRate)
			} else {
				fmt.Fprintf(os.Stderr, `{"event":"sync_progress","resource":"%s","fetched":%d}`+"\n", resource, atomic.LoadInt64(&progressCount))
			}
		}

		// Save cursor after each page for resumability
		if err := db.SaveSyncState(resource, nextCursor, totalCount); err != nil {
			// Non-fatal: log and continue
			fmt.Fprintf(os.Stderr, "\nwarning: failed to save sync state for %s: %v\n", resource, err)
		}

		pagesFetched++
		if maxPages > 0 && pagesFetched >= maxPages {
			if humanFriendly {
				fmt.Fprintf(os.Stderr, "\n  %s: reached --max-pages limit (%d pages, %d items)\n", resource, maxPages, totalCount)
			}
			break
		}

		// Determine if there are more pages
		if !hasMore || len(items) < pageSize.limit || nextCursor == "" {
			break
		}

		cursor = nextCursor
	}

	// Final sync state: clear cursor (sync is complete), update count
	_ = db.SaveSyncState(resource, "", totalCount)

	if !humanFriendly {
		fmt.Fprintf(os.Stderr, `{"event":"sync_complete","resource":"%s","total":%d,"duration_ms":%d}`+"\n", resource, totalCount, time.Since(started).Milliseconds())
	}

	return syncResult{Resource: resource, Count: totalCount, Duration: time.Since(started)}
}

// paginationDefaults holds the resolved pagination parameter names and page size.
type paginationDefaults struct {
	cursorParam string
	limitParam  string
	limit       int
}

// PATCH: Slack uses "cursor" as the pagination param for conversations.list, not "after".
// Using "after" causes Slack to ignore the cursor and re-fetch the first page on every request.
func determinePaginationDefaults() paginationDefaults {
	return paginationDefaults{
		cursorParam: "cursor",
		limitParam:  "limit",
		limit:       100,
	}
}

// determineSinceParam returns the query parameter name for incremental sync filtering.
func determineSinceParam() string {
	return "since"
}

// extractPageItems attempts to extract an array of items and pagination cursor from a response.
// It tries multiple strategies:
// 1. Direct JSON array
// 2. Common wrapper keys: "data", "results", "items", "records", "nodes", "entries"
// It also extracts the next cursor from common response fields.
func extractPageItems(data json.RawMessage, cursorParam string) ([]json.RawMessage, string, bool) {
	// Strategy 1: direct array
	var items []json.RawMessage
	if err := json.Unmarshal(data, &items); err == nil {
		return items, "", false
	}

	// Strategy 2: object with known wrapper keys
	var envelope map[string]json.RawMessage
	if err := json.Unmarshal(data, &envelope); err != nil {
		return nil, "", false
	}

	// Try common item keys (including Slack-specific wrapper keys)
	itemKeys := []string{"data", "results", "items", "records", "nodes", "entries",
		"channels", "members", "messages", "files", "users", "usergroups",
		"reminders", "stars", "pins", "emoji", "reactions"}
	for _, key := range itemKeys {
		if raw, ok := envelope[key]; ok {
			if err := json.Unmarshal(raw, &items); err == nil && len(items) > 0 {
				nextCursor, hasMore := extractPaginationFromEnvelope(envelope, cursorParam)
				return items, nextCursor, hasMore
			}
		}
	}

	return nil, "", false
}

// extractPaginationFromEnvelope extracts cursor and has_more from a response envelope.
func extractPaginationFromEnvelope(envelope map[string]json.RawMessage, cursorParam string) (string, bool) {
	var nextCursor string
	var hasMore bool

	// Try Slack-style response_metadata.next_cursor first
	if raw, ok := envelope["response_metadata"]; ok {
		var meta map[string]json.RawMessage
		if err := json.Unmarshal(raw, &meta); err == nil {
			if cursorRaw, ok := meta["next_cursor"]; ok {
				var s string
				if err := json.Unmarshal(cursorRaw, &s); err == nil && s != "" {
					nextCursor = s
				}
			}
		}
	}

	// Try common cursor field names
	if nextCursor == "" {
		cursorKeys := []string{
			"next_cursor", "nextCursor", "cursor", "next_page_token",
			"nextPageToken", "page_token", "after", "end_cursor", "endCursor",
		}
		for _, key := range cursorKeys {
			if raw, ok := envelope[key]; ok {
				var s string
				if err := json.Unmarshal(raw, &s); err == nil && s != "" {
					nextCursor = s
					break
				}
			}
		}
	}

	// Try common has_more field names
	hasMoreKeys := []string{"has_more", "hasMore", "has_next", "hasNext", "next_page"}
	for _, key := range hasMoreKeys {
		if raw, ok := envelope[key]; ok {
			if err := json.Unmarshal(raw, &hasMore); err == nil {
				break
			}
		}
	}

	// If we found a cursor, assume there are more pages even without explicit has_more
	if nextCursor != "" && !hasMore {
		hasMore = true
	}

	return nextCursor, hasMore
}

// upsertSingleObject stores a non-array API response as a single record.
func upsertSingleObject(db *store.Store, resource string, data json.RawMessage) error {
	var obj map[string]any
	if err := json.Unmarshal(data, &obj); err != nil {
		// Not a JSON object either - store raw under resource name
		return db.Upsert(resource, resource, data)
	}

	id := extractID(obj)
	if id == "" {
		id = resource
	}

	switch resource {
	default:
		return db.Upsert(resource, id, data)
	}
}

// parseSinceDuration converts human-friendly duration strings into a time.Time.
// Supported formats: "7d" (days), "24h" (hours), "30m" (minutes), "1w" (weeks).
func parseSinceDuration(s string) (time.Time, error) {
	re := regexp.MustCompile(`^(\d+)([dhwm])$`)
	matches := re.FindStringSubmatch(strings.TrimSpace(s))
	if matches == nil {
		return time.Time{}, fmt.Errorf("expected format like 7d, 24h, 1w, or 30m")
	}

	n, err := strconv.Atoi(matches[1])
	if err != nil {
		return time.Time{}, err
	}

	now := time.Now()
	switch matches[2] {
	case "d":
		return now.Add(-time.Duration(n) * 24 * time.Hour), nil
	case "h":
		return now.Add(-time.Duration(n) * time.Hour), nil
	case "w":
		return now.Add(-time.Duration(n) * 7 * 24 * time.Hour), nil
	case "m":
		return now.Add(-time.Duration(n) * time.Minute), nil
	default:
		return time.Time{}, fmt.Errorf("unknown unit %q", matches[2])
	}
}

func defaultSyncResources() []string {
	return []string{
		"conversations",
		"emoji",
		"files",
		"messages",
		"reactions",
		"reminders",
		"stars",
		"usergroups",
		"users",
	}
}

// syncResourcePath maps resource names to their actual API endpoint paths.
// For REST APIs this is typically "/<resource>". For non-REST APIs (e.g., Steam)
// this preserves the actual endpoint path like "/ISteamApps/GetAppList/v2".
func syncResourcePath(resource string) string {
	paths := map[string]string{
		// PATCH: exclude mpim,im types — they require mpim:read scope which typical bot tokens lack.
		// Slack returns ok:false with missing_scope error for those types, causing a corrupt single-record store.
		"conversations": "/conversations.list?types=public_channel,private_channel",
		"emoji":         "/emoji.list",
		"files":         "/files.list",
		"reactions":     "/reactions.list",
		"reminders":     "/reminders.list",
		"stars":         "/stars.list",
		"usergroups":    "/usergroups.list",
		"users":         "/users.list",
	}
	if p, ok := paths[resource]; ok {
		return p
	}
	return "/" + resource
}

func extractID(obj map[string]any) string {
	for _, key := range []string{"id", "ID", "uuid", "slug", "name"} {
		if v, ok := obj[key]; ok {
			return fmt.Sprintf("%v", v)
		}
	}
	return ""
}

func syncMessagesResource(c interface {
	Get(string, map[string]string) (json.RawMessage, error)
	RateLimit() float64
}, db *store.Store, sinceTS string, full bool, started time.Time) syncResult {
	var totalCount int
	_, lastSynced, _, _ := db.GetSyncState("messages")
	oldest := ""
	if sinceTS != "" {
		if ts, err := time.Parse(time.RFC3339, sinceTS); err == nil {
			oldest = strconv.FormatInt(ts.Unix(), 10)
		}
	} else if !lastSynced.IsZero() && !full {
		oldest = strconv.FormatInt(lastSynced.Unix(), 10)
	}

	channels, err := db.List("conversations", 0)
	if err != nil {
		return syncResult{Resource: "messages", Err: fmt.Errorf("listing conversations: %w", err), Duration: time.Since(started)}
	}
	if len(channels) == 0 {
		return syncResult{Resource: "messages", Err: fmt.Errorf("no conversations found in local store; sync conversations first"), Duration: time.Since(started)}
	}

	var progressCount int64
	for _, channel := range channels {
		var conversation map[string]any
		if err := json.Unmarshal(channel, &conversation); err != nil {
			return syncResult{Resource: "messages", Count: totalCount, Err: fmt.Errorf("parsing conversation: %w", err), Duration: time.Since(started)}
		}
		channelID := extractID(conversation)
		if channelID == "" {
			continue
		}

		cursor := ""
		for {
			params := map[string]string{"channel": channelID, "limit": "200"}
			if cursor != "" {
				params["cursor"] = cursor
			}
			if oldest != "" {
				params["oldest"] = oldest
			}

			data, err := c.Get("/conversations.history", params)
			if err != nil {
				return syncResult{Resource: "messages", Count: totalCount, Err: fmt.Errorf("fetching messages for %s: %w", channelID, err), Duration: time.Since(started)}
			}

			var envelope struct {
				Messages         []json.RawMessage `json:"messages"`
				ResponseMetadata struct {
					NextCursor string `json:"next_cursor"`
				} `json:"response_metadata"`
			}
			if err := json.Unmarshal(data, &envelope); err != nil {
				return syncResult{Resource: "messages", Count: totalCount, Err: fmt.Errorf("parsing messages for %s: %w", channelID, err), Duration: time.Since(started)}
			}

			for _, raw := range envelope.Messages {
				var msg struct {
					User       string          `json:"user"`
					Ts         string          `json:"ts"`
					ThreadTS   string          `json:"thread_ts"`
					Text       string          `json:"text"`
					ReplyCount int             `json:"reply_count"`
					Reactions  json.RawMessage `json:"reactions"`
				}
				if err := json.Unmarshal(raw, &msg); err != nil {
					return syncResult{Resource: "messages", Count: totalCount, Err: fmt.Errorf("parsing message in %s: %w", channelID, err), Duration: time.Since(started)}
				}
				if msg.Ts == "" {
					continue
				}
				reactionsJSON := "[]"
				if len(msg.Reactions) > 0 {
					reactionsJSON = string(msg.Reactions)
				}
				if err := db.UpsertMessage(channelID, msg.User, msg.Ts, msg.ThreadTS, msg.Text, msg.ReplyCount, reactionsJSON, raw); err != nil {
					return syncResult{Resource: "messages", Count: totalCount, Err: fmt.Errorf("storing message %s: %w", msg.Ts, err), Duration: time.Since(started)}
				}
				totalCount++
				atomic.AddInt64(&progressCount, 1)
			}

			currentRate := c.RateLimit()
			if humanFriendly {
				if currentRate > 0 {
					fmt.Fprintf(os.Stderr, "\r  messages: %d synced [%.1f req/s]", atomic.LoadInt64(&progressCount), currentRate)
				} else {
					fmt.Fprintf(os.Stderr, "\r  messages: %d synced", atomic.LoadInt64(&progressCount))
				}
			}

			cursor = envelope.ResponseMetadata.NextCursor
			if cursor == "" {
				break
			}
			if err := db.SaveSyncState("messages", cursor, totalCount); err != nil {
				fmt.Fprintf(os.Stderr, "\nwarning: failed to save sync state for messages: %v\n", err)
			}
		}
	}

	_ = db.SaveSyncState("messages", "", totalCount)
	if !humanFriendly {
		fmt.Fprintf(os.Stderr, `{"event":"sync_complete","resource":"messages","total":%d,"duration_ms":%d}`+"\n", totalCount, time.Since(started).Milliseconds())
	}
	return syncResult{Resource: "messages", Count: totalCount, Duration: time.Since(started)}
}
